import{_ as a,o as e,c as r,R as t}from"./chunks/framework.o-1c6b6b.js";const N=JSON.parse('{"title":"ACMP","description":"7-nd，从GNN能量函数优化的角度提出引力和斥力的观念解决过平滑和在异配图上表现较差的问题，参考Acmp:Allen-cahn message passing with attractive and repulsive forces for graph neural networks","frontmatter":{"date":"2023-12-10T00:00:00.000Z","title":"ACMP","tags":["GNN","ACMP"],"description":"7-nd，从GNN能量函数优化的角度提出引力和斥力的观念解决过平滑和在异配图上表现较差的问题，参考Acmp:Allen-cahn message passing with attractive and repulsive forces for graph neural networks"},"headers":[],"relativePath":"posts/GNN-ACMP.md","filePath":"posts/GNN-ACMP.md"}'),o={name:"posts/GNN-ACMP.md"},i=t('<h1 id="acmp" tabindex="-1">ACMP <a class="header-anchor" href="#acmp" aria-label="Permalink to &quot;ACMP&quot;">​</a></h1><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><ul><li>主要了解GNNs考虑信息传递上的模型表示。事实上很多流行的GNN模型如GCN, GAT, GIN都可以表示为<a href="https://arxiv.org/abs/1806.01261" target="_blank" rel="noreferrer">MP</a>形式。</li><li>了解本文主要解决的两个问题：过平滑与异配图表现欠佳</li><li>介绍交互粒子动力学下(即省略GNNs模型中的非线性层和参数矩阵的作用仅考虑粒子交互过程)下的模型GRAND(在[Chamberlain et al. (2021)][<a href="https://arxiv.org/abs/2106.10934" target="_blank" rel="noreferrer">https://arxiv.org/abs/2106.10934</a>]提出)。</li><li>了解狄利克雷能量，及狄利克雷能量与过平滑、粒子交互系统的关系。</li></ul><h3 id="message-passing" tabindex="-1">Message Passing <a class="header-anchor" href="#message-passing" aria-label="Permalink to &quot;Message Passing&quot;">​</a></h3><h3 id="heterophily-problems" tabindex="-1">Heterophily problems <a class="header-anchor" href="#heterophily-problems" aria-label="Permalink to &quot;Heterophily problems&quot;">​</a></h3><p>对于GNNs在异配图上表现差的分析可以见文章<a href="https://arxiv.org/abs/2210.07606" target="_blank" rel="noreferrer">Revisiting Heterophily For Graph Neural Networks</a>。</p><h3 id="" tabindex="-1"><a class="header-anchor" href="#" aria-label="Permalink to &quot;&quot;">​</a></h3><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>主要有两个考虑，一是添加斥力，二是防止因斥力导致特征发散到无穷的情况发生。</p><h2 id="experiments" tabindex="-1">Experiments <a class="header-anchor" href="#experiments" aria-label="Permalink to &quot;Experiments&quot;">​</a></h2><h2 id="theory" tabindex="-1">Theory <a class="header-anchor" href="#theory" aria-label="Permalink to &quot;Theory&quot;">​</a></h2><p>理论依据，能量角度。</p>',12),s=[i];function n(l,h,p,c,d,m){return e(),r("div",null,s)}const _=a(o,[["render",n]]);export{N as __pageData,_ as default};
